import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import TrustBar from './components/TrustBar';
import ValueProp from './components/ValueProp';
import HowItWorks from './components/HowItWorks';
import Categories from './components/Categories';
import AIFeature from './components/AIFeature';
import Footer from './components/Footer';
import CreatorModal from './components/CreatorModal';

const App: React.FC = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);

  const openModal = () => setIsModalOpen(true);
  const closeModal = () => setIsModalOpen(false);

  return (
    <div className="min-h-screen">
      <Navbar onOpenModal={openModal} />

      <main>
        <Hero onOpenModal={openModal} />
        <TrustBar />
        <ValueProp />
        <HowItWorks />
        <Categories />
        <AIFeature />
      </main>

      <Footer />

      {isModalOpen && <CreatorModal isOpen={isModalOpen} onClose={closeModal} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Globe, Menu, X } from 'lucide-react';

interface NavbarProps {
  onOpenModal: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ onOpenModal }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${
      isScrolled ? 'bg-white shadow-md py-3' : 'bg-transparent py-5'
    }`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          {/* Logo */}
          <div className="flex items-center">
            <span className={`text-2xl font-bold tracking-tight ${isScrolled ? 'text-primary' : 'text-primary md:text-white'}`}>
              UAE<span className="text-secondary">Creators</span>
            </span>
          </div>

          {/* Desktop Nav Links */}
          <div className="hidden md:flex items-center space-x-8">
            <a href="#brands" className={`font-medium hover:text-secondary transition-colors ${isScrolled ? 'text-dark' : 'text-white'}`}>For Brands</a>
            <a href="#creators" className={`font-medium hover:text-secondary transition-colors ${isScrolled ? 'text-dark' : 'text-white'}`}>For Creators</a>
            <a href="#how-it-works" className={`font-medium hover:text-secondary transition-colors ${isScrolled ? 'text-dark' : 'text-white'}`}>How it Works</a>
            <a href="#pricing" className={`font-medium hover:text-secondary transition-colors ${isScrolled ? 'text-dark' : 'text-white'}`}>Pricing</a>
          </div>

          {/* Desktop Actions */}
          <div className="hidden md:flex items-center space-x-4">
            <button className={`flex items-center text-sm font-medium ${isScrolled ? 'text-dark' : 'text-white'}`}>
              <Globe className="w-4 h-4 mr-1" />
              <span>EN | AR</span>
            </button>
            <button className={`px-4 py-2 text-sm font-semibold rounded-lg border transition-all ${
              isScrolled 
                ? 'border-primary text-primary hover:bg-primary hover:text-white' 
                : 'border-white text-white hover:bg-white hover:text-primary'
            }`}>
              Brand Login
            </button>
            <button 
              onClick={onOpenModal}
