          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="md:hidden bg-white absolute top-full left-0 w-full shadow-xl border-t border-gray-100 p-6 flex flex-col space-y-4">
          <a href="#brands" onClick={() => setIsMobileMenuOpen(false)} className="text-dark font-medium py-2">For Brands</a>
          <a href="#creators" onClick={() => setIsMobileMenuOpen(false)} className="text-dark font-medium py-2">For Creators</a>
          <a href="#how-it-works" onClick={() => setIsMobileMenuOpen(false)} className="text-dark font-medium py-2">How it Works</a>
