import React, { useState } from 'react';
import { X, ChevronRight, ChevronLeft, CheckCircle2, AlertCircle } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface CreatorModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const CreatorModal: React.FC<CreatorModalProps> = ({ isOpen, onClose }) => {
  const [step, setStep] = useState(1);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    fullName: '',
    age: '',
    country: 'United Arab Emirates',
    email: '',
    phone: '',
    instagram: '',
    tiktok: '',
    otherSocial: '',
    hasLicense: '',
    hasExperience: '',
    openToUnpaid: '',
    style: '',
    consentAge: false,
    consentContact: false
  });

  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'checkbox' ? (e.target as HTMLInputElement).checked : value;

    setFormData(prev => ({ ...prev, [name]: val }));

    // Immediate validation for age
    if (name === 'age' && parseInt(value) < 18) {
      setErrors(prev => ({ ...prev, age: "Due to UAE regulations, applicants must be 18 years or older." }));
    } else if (name === 'age') {
      setErrors(prev => {
        const newErrs = { ...prev };
        delete newErrs.age;
        return newErrs;
      });
    }
  };

  const validateStep = () => {
    const newErrors: { [key: string]: string } = {};
    if (step === 1) {
      if (!formData.fullName) newErrors.fullName = "Name is required";
      if (!formData.age || parseInt(formData.age) < 18) newErrors.age = "Must be 18 or older";
      if (!formData.email || !/\S+@\S+\.\S+/.test(formData.email)) newErrors.email = "Valid email is required";
    }
    if (step === 2) {
      if (!formData.instagram && !formData.tiktok) newErrors.social = "At least one social handle is required";
    }
    if (step === 4) {
      if (!formData.consentAge || !formData.consentContact) newErrors.consent = "You must agree to all terms";
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const nextStep = () => {
    if (validateStep()) {
      setStep(prev => prev + 1);
    }
  };

  const prevStep = () => setStep(prev => prev - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateStep()) {
      setIsSubmitted(true);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      {/* Overlay */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-primary/60 backdrop-blur-sm"
      ></motion.div>

      {/* Modal Card */}
      <motion.div 
        initial={{ scale: 0.9, opacity: 0, y: 20 }}
        animate={{ scale: 1, opacity: 1, y: 0 }}
        className="relative bg-white w-full max-w-xl rounded-3xl shadow-2xl overflow-hidden min-h-[500px] flex flex-col"
      >
        {/* Close Button */}
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 p-2 text-gray-400 hover:text-primary transition-colors z-20"
        >
          <X size={24} />
        </button>

        {!isSubmitted ? (
          <>
            {/* Header & Progress */}
            <div className="p-8 pb-4">
              <h3 className="text-2xl font-bold text-primary mb-2">Creator Application</h3>
              <p className="text-gray-500 text-sm mb-6">Join the #1 community in the UAE</p>

              <div className="relative h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
                <motion.div 
                  className="absolute top-0 left-0 h-full bg-secondary"
                  initial={{ width: '0%' }}
                  animate={{ width: `${(step / 4) * 100}%` }}
                ></motion.div>
              </div>
              <div className="flex justify-between mt-2 text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                <span>Info</span>
                <span>Socials</span>
                <span>Experience</span>
                <span>Consent</span>
              </div>
            </div>

            {/* Form Steps */}
            <div className="flex-1 p-8 pt-4 overflow-y-auto">
              <AnimatePresence mode="wait">
                {step === 1 && (
                  <motion.div 
                    key="step1"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="space-y-5"
                  >
                    <div>
                      <label className="block text-sm font-bold text-primary mb-2">Full Name</label>
                      <input 
                        name="fullName"
                        value={formData.fullName}
                        onChange={handleInputChange}
                        placeholder="e.g. Sarah Ahmed"
                        className={`w-full p-3 bg-gray-50 border rounded-xl outline-none transition-all ${errors.fullName ? 'border-red-500' : 'border-gray-200 focus:border-secondary'}`}
                      />
                      {errors.fullName && <p className="text-red-500 text-xs mt-1">{errors.fullName}</p>}
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-sm font-bold text-primary mb-2">Age</label>
                        <input 
                          name="age"
                          type="number"
                          value={formData.age}
                          onChange={handleInputChange}
                          placeholder="25"
                          className={`w-full p-3 bg-gray-50 border rounded-xl outline-none transition-all ${errors.age ? 'border-red-500' : 'border-gray-200 focus:border-secondary'}`}
                        />
                        {errors.age && (
                          <div className="flex items-center mt-1 text-red-500 space-x-1">
